 private static int solve(String template, String search) {
        int ans = 0;
        Map<Character, TreeSet<Integer>> charIdxMap = new HashMap<>();
        for (int i = 0; i < template.length(); i++) {
            TreeSet<Integer> indices = charIdxMap.getOrDefault(template.charAt(i), new TreeSet<>());
            indices.add(i);
            charIdxMap.put(template.charAt(i), indices);
        }
        int prev = -1;
        for (char c : search.toCharArray()) {
            TreeSet<Integer> indices = charIdxMap.getOrDefault(c, new TreeSet<>());
            if (indices.isEmpty()) {
                return -1;
            }
            if (prev < 0) {
                prev = indices.first();
                ans = prev;
            } else {
                if(indices.higher(prev) != null) {
                    ans += indices.higher(prev) - prev;
                    prev = indices.higher(prev);
                } else {
                    int diff = template.length() - prev;
                    diff+= indices.first();
                    ans+= diff;
                    prev = indices.first();
                }
            }
        }
        return ans + 1;
    }
