Second Question : Prim's MST algo
```
 private static int solve(int[][] points){
        int ans = 0;
        int edges = 0;
        boolean[] visited = new boolean[points.length];
        visited[0] = true;
        while(edges < points.length -1){
            int min = Integer.MAX_VALUE;
            int next = -1;
            for(int i = 0; i < points.length; i++){
                if(visited[i]){
                    for(int j = 0; j < points.length; j++){
                        if(!visited[j]){
                            int dist = Math.min(Math.abs(points[i][0]- points[j][0]), Math.min(Math.abs(points[i][1]- points[j][1]), Math.abs(points[i][2]- points[j][2])));
                            if(min > dist){
                                next = j;
                                min = dist;
                            }
                        }
                    }
                }
            }
            visited[next] = true;
            ans+= min;
            edges++;
        }
        return ans;
    }
